-          // be sometimes)
-          KDL::VelocityProfile_Spline spline_calc;
-          ROS_DEBUG_STREAM( "---------------Begin interpolating joint point---------------");
-
-          for (size_t i = 0; i < p1.positions.size(); ++i)
