+int main(int argc, char *argv[])
+{
+  rclcpp::init(argc, argv);
+  rclcpp::spin(std::make_shared<turtlebot3_manipulation_teleop_joystick::TurtleBot3ManipulationTeleopJoystick>());
+  rclcpp::shutdown();
+
+  return 0;
+}

